const input = $input.first().json;
const body = input.body || {};
const userId = body.userId || '';
const password = body.password || '';
if (!userId || !password) {
  return [{ json: { loginFailed: true, error: '아이디와 비밀번호를 입력해주세요', userId: '' } }];
}
return [{ json: { loginFailed: false, userId, password } }];

// 입력 검증에서 이미 실패했으면 패스
const prev = $('입력 검증').first().json;
if (prev.loginFailed) {
  return [{ json: { loginFailed: true, error: prev.error, userId: '' } }];
}

const raw = $input.first().json;
let body = '';
if (typeof raw === 'string') body = raw;
else if (typeof raw.data === 'string') body = raw.data;
else body = JSON.stringify(raw);

// MakeShop 로그인 실패: alert('ID 또는 비밀번호가 틀립니다.')
if (body.indexOf('틀립니다') !== -1 || body.indexOf('alert(') !== -1) {
  return [{ json: { loginFailed: true, error: '아이디 또는 비밀번호가 일치하지 않습니다', userId: '' } }];
}

return [{ json: { loginFailed: false, userId: prev.userId } }];

// 로그인 실패 플래그 확인
const loginCheck = $('로그인 결과 확인').first().json;
if (loginCheck.loginFailed) {
  return [{ json: { success: false, error: loginCheck.error } }];
}

const raw = $input.first().json;
let data = raw;
if (typeof raw.data === 'string') { try { data = JSON.parse(raw.data); } catch(e) {} }
let members = [];
if (data.list && Array.isArray(data.list)) {
  members = data.list;
} else if (data && typeof data === 'object') {
  members = Object.values(data).filter(v => typeof v === 'object' && v !== null && (v.userid || v.id));
}
if (members.length === 0) {
  return [{ json: { success: false, error: '회원 정보를 불러올 수 없습니다' } }];
}
const m = members[0];

const payload = JSON.stringify({
  userId: m.userid || m.id || '',
  name: m.name || '',
  email: m.email || '',
  phone: m.mobile || m.phone || '',
  grade: m.group_name || '',
  iat: Date.now(),
  exp: Date.now() + 7 * 24 * 60 * 60 * 1000
});
const token = Buffer.from(payload).toString('base64');

const user = {
  id: m.userid || m.id || '',
  name: m.name || '',
  email: m.email || '',
  phone: m.mobile || m.phone || '',
  isPartner: (m.group_name || '').includes('강사') || (m.group_no || '') !== '1',
  partnerGrade: null,
};

const gn = (m.group_name || '').toUpperCase();
if (gn.includes('AMBASSADOR') || gn.includes('앰배서더')) user.partnerGrade = 'AMBASSADOR';
else if (gn.includes('ATELIER') || gn.includes('아뜰리에')) user.partnerGrade = 'ATELIER';
else if (gn.includes('GARDEN') || gn.includes('가든')) user.partnerGrade = 'GARDEN';
else if (gn.includes('BLOOM') || gn.includes('블룸')) user.partnerGrade = 'BLOOM';

return [{ json: { success: true, data: { token, user } } }];
